import java.util.*;

class TweetCounts {

    private Map<String, List<Integer>> tweetTimes;

    public TweetCounts() {
        tweetTimes = new HashMap<>();
    }

    public void recordTweet(String tweetName, int time) {
        tweetTimes.computeIfAbsent(tweetName, k -> new ArrayList<>()).add(time);
    }

    public List<Integer> getTweetCountsPerFrequency(String freq, String tweetName, int startTime, int endTime) {
        List<Integer> times = tweetTimes.getOrDefault(tweetName, Collections.emptyList());
        int chunkSize = getChunkSize(freq);

        List<Integer> result = new ArrayList<>();
        int start = startTime;
        while (start <= endTime) {
            int end = Math.min(start + chunkSize - 1, endTime);
            int count = countTweetsInRange(times, start, end);
            result.add(count);
            start += chunkSize;
        }
        return result;
    }

    private int getChunkSize(String freq) {
        switch (freq) {
            case "minute": return 60;
            case "hour": return 3600;
            case "day": return 86400;
            default: throw new IllegalArgumentException("Invalid frequency");
        }
    }

    private int countTweetsInRange(List<Integer> times, int start, int end) {
        int left = binarySearch(times, start);
        int right = binarySearch(times, end + 1) - 1;
        return right - left + 1;
    }

    private int binarySearch(List<Integer> times, int target) {
        int left = 0, right = times.size();
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (times.get(mid) < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
}
